SELECT MAX(total_team_fantasy_points) AS highest_total_fantasy_points
FROM (
    SELECT team, SUM(fantasy_points) AS total_team_fantasy_points
    FROM players
    GROUP BY team
) AS team_fantasy_points;

external_knowledge:
- 'implied team total' is a projection or expectation of the team's total score for the game;
- 'fantasy points' are points scored by a player in a fantasy sports league;
- 'average fantasy points' refers to the mean fantasy points scored by all players in the `players` table.

- 'Treasure' refers to the total fantasy points scored by the team;
- 'Voyages' refers to the number of games played by the team;
- 'Combined metric' is the sum of the total fantasy points and the number of games played.

- "shining brightly" refers to teams with players who score high in fantasy points;
- "averaging more than 100 fantasy points" means the average fantasy points per player in the team is greater than 100;
- "from the most luminous to the least" means the results are ordered by the average fantasy points in descending order.

- "top 5 players" refers to the players with the highest projected weekly points (wProjection) in each team;
- "total salary for each team's top 5 players" is the sum of the salaries of these top 5 players;
- "average fantasy points" is the mean of the fantasy points scored by all players in the team.

- "Wide receiver" (WR) is a position in American football where players are typically responsible for catching passes from the quarterback.;
- "Fantasy points" are a scoring system used in fantasy sports to evaluate player performance based on real-life statistics.;
- "Away game" refers to a game played by a team in a venue that is not their home field.;
- "Total average fantasy points" is calculated by multiplying the average fantasy points per game by the total number of games played by the team.

sql:
SELECT MAX(avg_fantasy_points)
FROM (
  SELECT AVG(fantasy_points) AS avg_fantasy_points
  FROM players
  GROUP BY fantasy_position
);

external_knowledge:
